package com.travelassistant.consultation.ai;import static org.assertj.core.api.Assertions.assertThat;import java.time.Duration;import java.util.List;import org.junit.jupiter.api.Test;
class StubConsultationProviderRealtimeTest {@Test void acknowledgesRealtimeContextOnlyWhenPresent(){var provider=new StubConsultationProvider(Duration.ZERO);var withData=provider.answer(new ConsultationPrompt(List.of(new ConsultationPrompt.PromptMessage("user","<realtime-data encoding=\"base64-json\">e30=</realtime-data>"),new ConsultationPrompt.PromptMessage("user","天气？"))));assertThat(withData.content()).startsWith("已结合本次带来源的数据");var without=provider.answer(new ConsultationPrompt(List.of(new ConsultationPrompt.PromptMessage("user","天气？"))));assertThat(without.content()).doesNotContain("已结合本次");}}
